function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userRole, setUserRole] = useState(null); // 'cliente' o 'vendedor'

  useEffect(() => {
    const role = localStorage.getItem('user-role');
    const token = localStorage.getItem('token-falso');
    if (token) {
      setIsLoggedIn(true);
      setUserRole(role);
    }
  }, []);

  return (
    <Router>
      <Header isLoggedIn={isLoggedIn} userRole={userRole} cerrarSesion={cerrarSesion} />
      <Routes>
        <Route path="/" element={<Home />} />

        {/* RUTA PROTEGIDA PARA VENDEDORES */}
        <Route path="/dashboard" element={
          isLoggedIn && userRole === 'vendedor' ? <Dashboard /> : <Navigate to="/login" />
        } />

        {/* RUTA PARA CLIENTES (Buscador de productos) */}
        <Route path="/buscar" element={<VistaClienteBusqueda />} />

        <Route path="/login" element={<Login setIsLoggedIn={setIsLoggedIn} setUserRole={setUserRole} />} />
      </Routes>
    </Router>
  );
}
